import{_ as a,c as e,o as t,a1 as o}from"./chunks/framework.B00KZdpF.js";const g=JSON.parse('{"title":"","description":"","frontmatter":{},"headers":[],"relativePath":"zh-CN/guide/getting-started.md","filePath":"zh-CN/guide/getting-started.md","lastUpdated":1714661304000}'),r={name:"zh-CN/guide/getting-started.md"},s=o('<h2 id="napcatqq" tabindex="-1">NapCatQQ <a class="header-anchor" href="#napcatqq" aria-label="Permalink to &quot;NapCatQQ&quot;">​</a></h2><p>NapCat 是基于NT QQ 客户端本体实现的QQ Bot框架,稳定安全，快速部署。</p><h2 id="启动前需要了解的三两事" tabindex="-1">启动前需要了解的三两事 <a class="header-anchor" href="#启动前需要了解的三两事" aria-label="Permalink to &quot;启动前需要了解的三两事&quot;">​</a></h2><p><strong>（!你给我好好读三遍）</strong></p><ol><li>NapCat 是基于NT QQ 客户端本体实现的QQ Bot框架，所以说需要<strong>提前安装好QQ</strong>才能运行NapCat哦</li><li>NapCat 在线时，你不能使用PC QQ客户端实现人鸡合一，但是可以选择同步登录移动客户端</li><li>NapCat 每个版本基于<strong>不同版本 QQ</strong>开发，下载QQ时，你选择可以到侧边栏<strong>版本日志</strong>查看对应的QQ版本的</li><li>NapCat 不同于协议实现，基于QQ客户端当然QQ客户端上干不了的事，NapCat &gt;_&lt; 当然也是不行的!</li></ol><h2 id="启动-快快端上来吧" tabindex="-1">启动 - 快快端上来吧 <a class="header-anchor" href="#启动-快快端上来吧" aria-label="Permalink to &quot;启动 - 快快端上来吧&quot;">​</a></h2><h3 id="如果你是-windows-用户" tabindex="-1">如果你是 Windows 用户 <a class="header-anchor" href="#如果你是-windows-用户" aria-label="Permalink to &quot;如果你是 Windows 用户&quot;">​</a></h3><details class="details custom-block"><summary>启动教程</summary><p>安装好对应版本QQ后 我们大多数情况只需要解压NapCat放到你想的的任何地方，双击 <code>napcat.bat</code> 就可以运行啦</p><p>等等! 如果你出现乱码可以尝试双击 <code>napcat-utf8.bat</code>启动</p><p>除了上面的方法你还可以使用powershell启动NapCat（如果启动好了，就不用看下面的这种启动方式了）</p><p>启动powershell运行<code>powershell ./napcat.ps1</code>, 或者 <code>napcat.bat</code>，如果出现乱码，可以尝试运行<code>napcat-utf8.ps1</code> 或 <code>napcat-utf8.bat</code></p><p><em>如果出现 powershell 运行不了，可以尝试 <code>powershell.exe -ExecutionPolicy Bypass -File &quot;.\\napcat.ps1&quot;</code></em></p><p><strong>推荐使用 bat 运行，powershell 会自身占用 20MB 左右的内存</strong></p></details><h3 id="如果你是-linux-docker用户请看" tabindex="-1">如果你是 Linux Docker用户请看 <a class="header-anchor" href="#如果你是-linux-docker用户请看" aria-label="Permalink to &quot;如果你是 Linux Docker用户请看&quot;">​</a></h3><details class="details custom-block"><summary>启动教程</summary><p><a href="https://github.com/NapNeko/NapCat-Docker" target="_blank" rel="noreferrer">详细教程</a></p></details><h3 id="如果你是-linux-不想用-docker" tabindex="-1">如果你是 Linux 不想用 Docker <a class="header-anchor" href="#如果你是-linux-不想用-docker" aria-label="Permalink to &quot;如果你是 Linux 不想用 Docker&quot;">​</a></h3><details class="details custom-block"><summary>启动教程</summary><p>运行<code>napcat.sh</code></p></details><h3 id="启动之后" tabindex="-1">启动之后 <a class="header-anchor" href="#启动之后" aria-label="Permalink to &quot;启动之后&quot;">​</a></h3><p>恭喜你，如果看到这里，你可能已经启动或者尝试启动了NapCat，你是否遇到崩溃与配置问题</p><p><a href="/zh-CN/guide/config">如何配置NapCat的基础设置</a></p><p><a href="/zh-CN/guide/faq">如何配置NapCat的语音发送</a> 参考 <code>语音、视频发送失败</code> 发生失败条目</p><p><a href="/zh-CN/guide/faq">遇到NapCat崩溃问题如何解决</a></p>',17),i=[s];function l(c,d,n,p,h,u){return t(),e("div",null,i)}const N=a(r,[["render",l]]);export{g as __pageData,N as default};
